from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI parser instance
    cli = LeannCLI()

    # Parse the arguments
    parsed_args = cli.parse_args(args_list)

    # Initialize configuration dictionary
    config = {}

    # Extract common configuration parameters
    if hasattr(parsed_args, 'config'):
        config['config_path'] = parsed_args.config

    if hasattr(parsed_args, 'verbose'):
        config['verbose'] = parsed_args.verbose

    if hasattr(parsed_args, 'output'):
        config['output_path'] = parsed_args.output

    # Extract command-specific parameters based on command type
    if command_type == "build":
        # Extract build-specific parameters
        if hasattr(parsed_args, 'docs'):
            config['docs_paths'] = parsed_args.docs

        if hasattr(parsed_args, 'index'):
            config['index_path'] = parsed_args.index

        if hasattr(parsed_args, 'force'):
            config['force_rebuild'] = parsed_args.force

        if hasattr(parsed_args, 'threads'):
            config['threads'] = parsed_args.threads

    elif command_type == "search":
        # Extract search-specific parameters
        if hasattr(parsed_args, 'query'):
            config['query'] = parsed_args.query

        if hasattr(parsed_args, 'index'):
            config['index_path'] = parsed_args.index

        if hasattr(parsed_args, 'limit'):
            config['result_limit'] = parsed_args.limit

        if hasattr(parsed_args, 'threshold'):
            config['similarity_threshold'] = parsed_args.threshold

        if hasattr(parsed_args, 'format'):
            config['output_format'] = parsed_args.format

    # Add command type to config
    config['command_type'] = command_type

    return config

